create table dirkspzm32.db_ddl_log (
    event_id     number(10, 0),
    event_date   date,
    user_id      varchar2(30 char),
    object_name  varchar2(64 char),
    owner        varchar2(30 char),
    object_type  varchar2(30 char),
    system_event varchar2(30 char),
    machine      varchar2(64 char),
    program      varchar2(64 char)
);


